import java.util.Arrays;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        if (k <= 1) {
            return 0;
        }
        int nodeCount = (int) n;
        if (edges.length == 0) {
            return 0;
        }

        long max_time = 0;
        for (long[] edge : edges) {
            if (edge[2] > max_time) {
                max_time = edge[2];
            }
        }

        Arrays.sort(edges, (a, b) -> Long.compare(b[2], a[2]));

        long low = 0;
        long high = max_time;

        while (low < high) {
            long mid = low + (high - low) / 2;
            int comp = countComponents(nodeCount, edges, mid);
            if (comp >= k) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    private static int countComponents(int n, long[][] sortedEdges, long t) {
        DSU dsu = new DSU(n);
        for (long[] edge : sortedEdges) {
            if (edge[2] > t) {
                int u = (int) edge[0];
                int v = (int) edge[1];
                dsu.union(u, v);
            } else {
                break;
            }
        }
        return dsu.count;
    }

    static class DSU {
        int[] parent;
        int[] rank;
        int count;

        DSU(int n) {
            parent = new int[n];
            rank = new int[n];
            count = n;
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        void union(int x, int y) {
            int rx = find(x);
            int ry = find(y);
            if (rx == ry) {
                return;
            }
            if (rank[rx] < rank[ry]) {
                parent[rx] = ry;
            } else if (rank[ry] < rank[rx]) {
                parent[ry] = rx;
            } else {
                parent[rx] = ry;
                rank[ry]++;
            }
            count--;
        }
    }
}
